class Solution:
    def cycleLengthQueries(self, n, queries):
        def depth(v):
            return v.bit_length() - 1

        answer = []
        for a, b in queries:
            da, db = depth(a), depth(b)
            x, y = a, b
            if da > db:
                x >>= (da - db)
            elif db > da:
                y >>= (db - da)
            climb = 0
            while x != y:
                x >>= 1
                y >>= 1
                climb += 1
            distance = abs(da - db) + 2 * climb
            answer.append(distance + 1)
        return answer

