class Solution:
    def cycleLengthQueries(self, n, queries):
        answer = []
        for a, b in queries:
            x, y = a, b
            steps = 0
            while x != y:
                if x > y:
                    x //= 2
                else:
                    y //= 2
                steps += 1
            answer.append(steps + 1)
        return answer

