var cycleLengthQueries = function(n, queries) {
    const answer = [];
    for (const [a, b] of queries) {
        let x = a, y = b;
        let steps = 0;
        while (x !== y) {
            if (x > y) {
                x = Math.floor(x / 2);
            } else {
                y = Math.floor(y / 2);
            }
            steps++;
        }
        answer.push(steps + 1);
    }
    return answer;
};
